import { useState, useCallback } from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import { Toaster } from "react-hot-toast";

import Navbar        from "./components/Navbar";
import Hero          from "./components/Hero";
import Marquee       from "./components/Marquee";
import About         from "./components/About";
import Footer        from "./components/Footer";
import Lightbox      from "./components/Lightbox";
import BookingModal  from "./components/BookingModal";
import WorkPopup     from "./components/WorkPopup";

import FlowView from "./views/FlowView";
import GridView from "./views/GridView";
import MapView  from "./views/MapView";

import "./styles/globals.css";
import "./App.css";

/**
 * App
 * ───
 * Shared page layout and routing.
 */
export default function App() {
  const [activePhoto, setActivePhoto] = useState(null);
  const [bookingOpen, setBookingOpen] = useState(false);
  const [workPopupOpen, setWorkPopupOpen] = useState(false);

  const openLightbox  = useCallback((photo) => setActivePhoto(photo), []);
  const closeLightbox = useCallback(() => setActivePhoto(null), []);
  const navigateLightbox = useCallback((photo) => setActivePhoto(photo), []);

  const openBooking = useCallback(() => setBookingOpen(true), []);
  const closeBooking = useCallback(() => setBookingOpen(false), []);
  const openWorkPopup = useCallback(() => setWorkPopupOpen(true), []);
  const closeWorkPopup = useCallback(() => setWorkPopupOpen(false), []);

  return (
    <div className="app">
      <Navbar onBookClick={openBooking} />
      <Marquee />
      <Hero onWorkClick={openWorkPopup} />
      <About />

      <main className="app__main">
        <Routes>
          <Route path="/"     element={<Navigate to="/flow" replace />} />
          <Route path="/flow" element={<FlowView onPhotoClick={openLightbox} />} />
          <Route path="/grid" element={<GridView onPhotoClick={openLightbox} />} />
          <Route path="/map"  element={<MapView  onPhotoClick={openLightbox} />} />
        </Routes>
      </main>

      <Footer />
      <BookingModal isOpen={bookingOpen} onClose={closeBooking} />
      <WorkPopup isOpen={workPopupOpen} onClose={closeWorkPopup} />
      <Toaster
        position="top-right"
        toastOptions={{
          style: {
            background: "#11100d",
            color: "#f5ede0",
            border: "1px solid rgba(201,168,92,0.2)",
            boxShadow: "0 24px 60px rgba(0,0,0,0.18)",
          },
        }}
      />
      <Lightbox
        photo={activePhoto}
        onClose={closeLightbox}
        onNavigate={navigateLightbox}
      />
    </div>
  );
}
